:\"https://woocommerce.com/wp-content/uploads/2012/08/ShipStation-Icon-1.png\";s:5:\"title\";s:11:\"ShipStation\";s:4:\"copy\";s:113:\"Ship your WooCommerce orders with confidence, save on top carriers, and automate your processes with ShipStation.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:57:\"https://woocommerce.com/products/shipstation-integration/\";}i:11;a:8:{s:4:\"slug\";s:57:\"orders-list-empty-body-estimated-delivery-and-pickup-date\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:34:\"estimated-delivery-and-pickup-date\";s:4:\"icon\";s:84:\"https://woocommerce.com/wp-content/uploads/2026/03/Estimated-order-delivery-time.png\";s:5:\"title\";s:40:\"Estimated Order Delivery and Pickup Date\";s:4:\"copy\";s:158:\"Show estimated order delivery date on your WooCommerce shop. Configure rules based on product, category, shipping country, shipping zone, and shipping method.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:68:\"https://woocommerce.com/products/estimated-delivery-and-pickup-date/\";}i:12;a:8:{s:4:\"slug\";s:46:\"orders-list-empty-body-dl-delivery-date-picker\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:23:\"dl-delivery-date-picker\";s:4:\"icon\";s:114:\"https://woocommerce.com/wp-content/uploads/2025/12/Delivery-Date-Picker-for-WooCommerce-Product-Icon-160x160-1.png\";s:5:\"title\";s:20:\"Delivery Date Picker\";s:4:\"copy\";s:209:\"Add a clear delivery or collection date selector, control the earliest selectable date with global or per-product lead times, and optionally block weekend bookings to match your real-world fulfilment schedule.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:57:\"https://woocommerce.com/products/dl-delivery-date-picker/\";}i:13;a:8:{s:4:\"slug\";s:44:\"orders-list-empty-body-product-stock-manager\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:21:\"product-stock-manager\";s:4:\"icon\";s:81:\"https://woocommerce.com/wp-content/upload