2:\"Get shipping rates from the FedEx API which handles both domestic and international parcels.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:55:\"https://woocommerce.com/products/fedex-shipping-module/\";}i:17;a:9:{s:4:\"slug\";s:42:\"product-edit-meta-tab-body-product-add-ons\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:15:\"product-add-ons\";s:4:\"icon\";s:96:\"https://woocommerce.com/wp-content/uploads/2013/05/Product_Addons_icon-marketplace-160x160-2.png\";s:5:\"title\";s:15:\"Product Add-Ons\";s:4:\"copy\";s:94:\"Offer add-ons like gift wrapping, special messages or other special options for your products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:49:\"https://woocommerce.com/products/product-add-ons/\";s:9:\"is_pinned\";b:1;}i:18;a:9:{s:4:\"slug\";s:42:\"product-edit-meta-tab-body-product-bundles\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:15:\"product-bundles\";s:4:\"icon\";s:97:\"https://woocommerce.com/wp-content/uploads/2012/07/Product_Bundles_icon-marketplace-160x160-2.png\";s:5:\"title\";s:15:\"Product Bundles\";s:4:\"copy\";s:84:\"Offer personalized product bundles, bulk discount packages, and assembled products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:49:\"https://woocommerce.com/products/product-bundles/\";s:9:\"is_pinned\";b:1;}i:19;a:9:{s:4:\"slug\";s:47:\"product-edit-meta-tab-body-woocommerce-bookings\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:20:\"woocommerce-bookings\";s:4:\"icon\";s:90:\"https://woocommerce.com/wp-content/uploads/2014/05/Bookings_icon-marketplace-160x160-1.png\";s:5:\"title\";s:20:\"WooCommerce Bookings\";s:4:\"copy\";s:101:\"Allow customers to book appointments, make reservations, or rent equipment without leaving your site.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:54:\"https://woocommerce.com/products/woocommerce-bookings/\";s:9:\"is_pinned\";b:1;}i:20;a:9:{s:4:\"slug\";s:52:\"product-edit-meta-tab-body-woocommerce-subscriptions\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:25:\"woocommerce-subscriptions\";s:4:\"icon\";s:99:\"https://woocommerce.com/wp-content/uploads/2012/09/Woo_Subscriptions_icon-marketplace-160x160-2.png\";s:5:\"title\";s:25:\"WooCommerce Subscriptions\";s:4:\"copy\";s:98:\"Let customers subscribe to your products or services and pay on a weekly, monthly or annual basis.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:59:\"https://woocommerce.com/products/woocommerce-subscriptions/\";s:9:\"is_pinned\";b:1;}i:21;a:9:{s:4:\"slug\";s:45:\"product-edit-meta-tab-body-composite-products\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:18:\"composite-products\";s:4:\"icon\";s:100:\"https://woocommerce.com/wp-content/uploads/2013/06/Composite_Products_icon-marketplace-160x160-1.png\";s:5:\"title\";s:18:\"Composite Products\";s:4:\"copy\";s:85:\"Create product kit builders and custom product configurators using existing products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:52:\"https://woocommerce.com/products/composite-products/\";s:9:\"is_pinned\";b:1;}i:22;a:8:{s:4:\"slug\";s:38:\"product-edit-meta-tab-body-force-sells\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:11:\"force-sells\";s:4:\"icon\";s:77:\"https://woocommerce.com/wp-content/uploads/2012/05/Kestrel-product-logo-1.png\";s:5:\"title\";s:11:\"Force Sells\";s:4:\"copy\";s:179:\"Link products together so they’re always purchased in the right combination. Perfect for required add-ons, bundled services, or products that only make sense when sold together.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:45:\"https://woocommerce.com/products/force-sells/\";}i:23;a:8:{s:4:\"slug\";s:64:\"product-edit-meta-tab-body-customer-upload-files-for-woocommerce\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:37:\"customer-upload-files-for-woocommerce\";s:4:\"icon\";s:67:\"https://woocommerce.com/wp-content/uploads/2020/09/Upload-files.jpg\";s:5:\"title\";s:21:\"Customer Upload Files\";s:4:\"copy\";s:144:\"Upload Files on the Product, Cart, and Checkout pages of your WooCommerce store and allow customers to provide necessary additional information.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:71:\"https://woocommerce.com/products/customer-upload-files-for-woocommerce/\";}i:24;a:8:{s:4:\"slug\";s:53:\"product-edit-meta-tab-body-restrict-product-purchases\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:26:\"restrict-product-purchases\";s:4:\"icon\";s:81:\"https://woocommerce.com/wp-content/uploads/2025/04/Plugify-product-Logos-01-1.png\";s:5:\"title\";s:26:\"Restrict Product Purchases\";s:4:\"copy\";s:178:\"Restrict Product Purchase for WooCommerce lets you limit product access by user role or membership plan. Only users with specific access can view or purchase restricted products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:60:\"https://woocommerce.com/products/restrict-product-purchases/\";}i:25;a:8:{s:4:\"slug\";s:61:\"product-edit-meta-tab-body-woocommerce-accommodation-bookings\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:34:\"woocommerce-accommodation-bookings\";s:4:\"icon\";s:90:\"https://woocommerce.com/wp-content/uploads/2016/01/icon-accommodation_bookings_160x160.png\";s:5:\"title\";s:34:\"WooCommerce Accommodation Bookings\";s:4:\"copy\";s:76:\"Book accommodation using WooCommerce and the WooCommerce Bookings extension.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:68:\"https://woocommerce.com/products/woocommerce-accommodation-bookings/\";}i:26;a:8:{s:4:\"slug\";s:52:\"product-edit-meta-tab-body-download-and-share-orders\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:25:\"download-and-share-orders\";s:4:\"icon\";s:68:\"https://woocommerce.com/wp-content/uploads/2025/02/ssscscsccs-01.png\";s:5:\"title\";s:25:\"Download and Share Orders\";s:4:\"copy\";s:181:\"Let customers download a professional PDF of any order and share it on WhatsApp, Facebook, Telegram, and 6 more platforms — in one click. Turn every order into a marketing moment.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:59:\"https://woocommerce.com/products/download-and-share-orders/\";}}s:7:\"updated\";i:1777960268;}', 'off'),
